const fs = require('node:fs')
const path = require('node:path')

const projectRoot = path.resolve(__dirname, '..')
const packageLockPath = path.join(projectRoot, 'package-lock.json')
const outputPath = path.join(
  projectRoot,
  'src',
  'renderer',
  'src',
  'generated',
  'bundled-licenses.ts'
)

const licenseEntries = [
  { name: '@electron-toolkit/preload', license: 'MIT' },
  { name: '@electron-toolkit/utils', license: 'MIT' },
  { name: '@fortawesome/fontawesome-free', license: 'CC-BY-4.0 AND OFL-1.1 AND MIT' },
  { name: 'buefy', license: 'MIT' },
  { name: 'electron', license: 'MIT' },
  { name: 'electron-updater', license: 'MIT' },
  { name: 'highcharts', license: 'https://www.highcharts.com/license' },
  { name: 'moment', license: 'MIT' },
  { name: 'nedb', license: 'MIT' },
  { name: 'qs', license: 'BSD-3-Clause' },
  { name: 'uuid', license: 'MIT' },
  { name: 'vue', license: 'MIT' },
  { name: 'vue-router', license: 'MIT' }
]

function packageLockKey(packageName) {
  return `node_modules/${packageName}`
}

function readPackageLock() {
  return JSON.parse(fs.readFileSync(packageLockPath, 'utf8'))
}

function toTsString(value) {
  return `'${value.replace(/\\/g, '\\\\').replace(/'/g, "\\'")}'`
}

function buildOutput(packageLock) {
  const packages = packageLock.packages || {}
  const licenseLines = licenseEntries.map((entry) => {
    const lockedPackage = packages[packageLockKey(entry.name)]
    if (!lockedPackage?.version) {
      throw new Error(`Package version not found in package-lock.json: ${entry.name}`)
    }
    return `  {
    name: ${toTsString(entry.name)},
    version: ${toTsString(lockedPackage.version)},
    license: ${toTsString(entry.license)}
  }`
  })

  return `// This file is generated by scripts/generate-bundled-licenses.js.
// Do not edit this file directly.

export type BundledLicense = {
  name: string
  version: string
  license: string
}

export const bundledLicenses: BundledLicense[] = [
${licenseLines.join(',\n')}
]
`
}

const packageLock = readPackageLock()
const output = buildOutput(packageLock)

fs.mkdirSync(path.dirname(outputPath), { recursive: true })
fs.writeFileSync(outputPath, output, 'utf8')
